#include "streamcluster.h"

using namespace std;

#define THREADS_PER_BLOCK 256
#define MAXBLOCKS 65536

float *work_mem_h;
float *coord_h;
float *gl_lower;
Point_Struct *p_h;

cl_mem work_mem_d;
cl_mem coord_d;
cl_mem center_table_d;
cl_mem switch_membership_d;
cl_mem p_d;

static int iter = 0;

static float
cl_dist(int p1, int p2, int num, int dim, float *coord_d)
{
	float retval = 0.0;
	for(int i = 0; i < dim; i++){
		float tmp = coord_d[(i*num)+p1] - coord_d[(i*num)+p2];
		retval += tmp * tmp;
	}
	return retval;
}

kernel void
kernel_compute_cost(int num, int dim, long x, Point_Struct *p, int K, int stride,
					float *coord_d, float *work_mem_d, int *center_table_d, char *switch_membership_d)
{
	const int tid = get_global_id(0);

	if(tid < num)
	{
		float *lower = &work_mem_d[tid*stride];

		float x_cost = cl_dist(tid, x, num, dim, coord_d) * p[tid].weight;

		if ( x_cost < p[tid].cost )
		{
			switch_membership_d[tid] = 1;
			lower[K] += x_cost - p[tid].cost;
		}
		else
		{
			lower[center_table_d[p[tid].assign]] += p[tid].cost - x_cost;
		}
	}
}

void allocDevMem(int num, int dim, int kmax)
{
	try{
		work_mem_d = _clMalloc((kmax + 1) * num * sizeof(float));
		center_table_d = _clMalloc(num * sizeof(int));
		switch_membership_d = _clMalloc(num * sizeof(char));
		p_d = _clMalloc(num * sizeof(Point_Struct));
		coord_d = _clMalloc(num * dim * sizeof(float));
	}
	catch(string msg){
		quit(&(msg[0]));
	}	
}

void allocHostMem(int num, int dim)
{
	coord_h = (float*) malloc( num * dim * sizeof(float) );
}

void freeDevMem()
{
	try{
		_clFree(work_mem_d);
		_clFree(center_table_d);
		_clFree(switch_membership_d);
		_clFree(p_d);
		_clFree(coord_d);

		_clFreeHost(1, work_mem_h);

		if(coord_h!=NULL)
			free(coord_h);
		if(gl_lower!=NULL)
			free(gl_lower);
		if(p_h!=NULL)
			free(p_h);
	}
	catch(string msg){
		quit(&(msg[0]));
	}	
}

void freeHostMem()
{
	free(coord_h);
}

float pgain( long x, Points *points, float z, long int *numcenters, int kmax, bool *is_center, int *center_table, char *switch_membership, bool isCoordChanged,
							double *serial_t, double *cpu_to_gpu_t, double *gpu_to_cpu_t, double *alloc_t, double *kernel_t, double *free_t)
{	
#ifdef PROFILE_TMP
	double tmp_t;
	double t_start, t_stop;
#endif

#ifdef PROFILE_TMP
	t_start = gettime();
#endif

	int stride	= *numcenters + 1;			
	int K		= *numcenters ;				
	int num		=  points->num;				
	int dim		=  points->dim;				
	int nThread =  num;						

	work_mem_h = (float*) malloc(stride * (nThread + 1) * sizeof(float) );

	if(iter == 0)
	{
		allocHostMem(num, dim);
	}

	int count = 0;
	for( int i=0; i<num; i++)
	{
		if( is_center[i] )
		{
			center_table[i] = count++;
		}
	}

	if(isCoordChanged || iter == 0)
	{
		for(int i=0; i<dim; i++)
		{
			for(int j=0; j<num; j++)
			{
				coord_h[ (num*i)+j ] = points->p[j].coord[i];
			}
		}
	}

#ifdef PROFILE_TMP
	t_stop = gettime();
	*serial_t += (t_stop - t_start);
	t_start = gettime();
#endif

#ifdef  TIMING
	gettimeofday(&tv_mem_alloc_start, NULL);
#endif
	work_mem_h = (float*)_clMallocHost(stride * (nThread + 1) * sizeof(float));
#ifdef  TIMING
    gettimeofday(&tv_mem_alloc_end, NULL);
    tvsub(&tv_mem_alloc_end, &tv_mem_alloc_start, &tv);
    mem_alloc_time += tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

	if( iter == 0 )
	{
		allocDevMem(num, dim, kmax);
	}

#ifdef PROFILE_TMP
	t_stop = gettime();
	*alloc_t += (t_stop - t_start);
	t_start = gettime();
#endif

	if(isCoordChanged || iter == 0)
	{
		_clMemcpyH2D(coord_d,  coord_h,	 num * dim * sizeof(float));
	}
	_clMemcpyH2D(center_table_d,  center_table,  num * sizeof(int));

	p_h = (Point_Struct*)malloc(num*sizeof(Point_Struct));
	for(int i=0; i<num; i++){
		p_h[i].weight = points->p[i].weight;
		p_h[i].assign = points->p[i].assign;
		p_h[i].cost = points->p[i].cost;
	}
	_clMemcpyH2D(p_d,  p_h,				   num * sizeof(Point_Struct));

	_clMemset((void*) switch_membership_d, 0,			num * sizeof(char));
	_clMemset((void*) work_mem_d,  		0, stride * (nThread + 1) * sizeof(float));

#ifdef PROFILE_TMP
	t_stop = gettime();
	*cpu_to_gpu_t += (t_stop - t_start);
	t_start = gettime();
#endif

	int num_blocks 	 = (int) ((float) (num + THREADS_PER_BLOCK - 1) / (float) THREADS_PER_BLOCK);
	int num_blocks_y = (int) ((float) (num_blocks + MAXBLOCKS - 1)  / (float) MAXBLOCKS);
	int num_blocks_x = (int) ((float) (num_blocks+num_blocks_y - 1) / (float) num_blocks_y);	

	int kernel_id = 1;
	int arg_idx = 0;

	_clSetArgs(kernel_id, arg_idx++, &num, sizeof(int));
	_clSetArgs(kernel_id, arg_idx++, &dim, sizeof(int));
	_clSetArgs(kernel_id, arg_idx++, &x, sizeof(long));
	_clSetArgs(kernel_id, arg_idx++, p_d);
	_clSetArgs(kernel_id, arg_idx++, &K, sizeof(int));
	_clSetArgs(kernel_id, arg_idx++, &stride, sizeof(int));
	_clSetArgs(kernel_id, arg_idx++, coord_d);
	_clSetArgs(kernel_id, arg_idx++, work_mem_d);
	_clSetArgs(kernel_id, arg_idx++, center_table_d);
	_clSetArgs(kernel_id, arg_idx++, switch_membership_d);

	_clInvokeKernel(kernel_id, num, THREADS_PER_BLOCK);
	_clFinish();

#ifdef PROFILE_TMP
	t_stop = gettime();
	*kernel_t += (t_stop - t_start);
	t_start = gettime();
#endif

	_clMemcpyD2H(work_mem_h, 		  work_mem_d, 	stride * (nThread + 1) * sizeof(float));
	_clMemcpyD2H(switch_membership, switch_membership_d,	 num * sizeof(char));

#ifdef PROFILE_TMP
	t_stop = gettime();
	*gpu_to_cpu_t += (t_stop - t_start);
	t_start = gettime();
#endif

	int number_of_centers_to_close = 0;
	float gl_cost_of_opening_x = z;
	gl_lower = &work_mem_h[stride * nThread];

	for(int i=0; i < num; i++)
	{
		if( is_center[i] )
		{
			float low = z;
		    for( int j = 0; j < num; j++ )
			{
				low += work_mem_h[ j*stride + center_table[i] ];
			}

		    gl_lower[center_table[i]] = low;

		    if ( low > 0 )
			{
				++number_of_centers_to_close;
				work_mem_h[i*stride+K] -= low;
		    }
		}
		gl_cost_of_opening_x += work_mem_h[i*stride+K];
	}

	if ( gl_cost_of_opening_x < 0 )
	{
		for(int i = 0; i < num; i++)
		{
			bool close_center = gl_lower[center_table[points->p[i].assign]] > 0 ;
			if ( switch_membership[i]=='1' || close_center )
			{
				points->p[i].cost = dist(points->p[i], points->p[x], dim) * points->p[i].weight;
				points->p[i].assign = x;
			}
		}

		for(int i = 0; i < num; i++)
		{
			if( is_center[i] && gl_lower[center_table[i]] > 0 )
			{
				is_center[i] = false;
			}
		}

		if( x >= 0 && x < num)
		{
			is_center[x] = true;
		}
		*numcenters = *numcenters + 1 - number_of_centers_to_close;
	}
	else
	{
		gl_cost_of_opening_x = 0;
	}

	free(work_mem_h);

#ifdef PROFILE_TMP
	t_stop = gettime();
	*serial_t += (t_stop - t_start);
	t_start = gettime();
#endif

#ifdef  TIMING
	gettimeofday(&tv_mem_alloc_start, NULL);
#endif
	_clFree(work_mem_d);
#ifdef  TIMING
    gettimeofday(&tv_mem_alloc_end, NULL);
    tvsub(&tv_mem_alloc_end, &tv_mem_alloc_start, &tv);
    mem_alloc_time += tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

#ifdef PROFILE_TMP
	t_stop = gettime();
	*free_t += (t_stop - t_start);
#endif
	iter++;
	return -gl_cost_of_opening_x;
}
